 28→function getPromotionRuntimePath(filename: string): string | null {
 29→  switch (filename) {
 30→    case 'Promo-Banner.png':
 31→      return 'changelog-promo-banner.png';
 32→    case 'Promo-Banner-cn.png':
 33→      return 'changelog-promo-banner-cn.png';
 34→    case 'Promo-Banner-jp.png':
 35→      return 'changelog-promo-banner-jp.png';
 36→    default:
 37→      return null;
 38→  }
 39→}
