 41→function getRuntimeUrl(path: string): string | null {
 42→  try {
 43→    const runtime = (
 44→      globalThis as typeof globalThis & {
 45→        browser?: { runtime?: { getURL?: (assetPath: string) => string } };
 46→        chrome?: { runtime?: { getURL?: (assetPath: string) => string } };
 47→      }
 48→    ).browser?.runtime;
 49→    const fallbackRuntime = (
 50→      globalThis as typeof globalThis & {
 51→        chrome?: { runtime?: { getURL?: (assetPath: string) => string } };
 52→      }
 53→    ).chrome?.runtime;
 54→    const getUrl = runtime?.getURL ?? fallbackRuntime?.getURL;
 55→    return typeof getUrl === 'function' ? getUrl(path) : null;
 56→  } catch {
 57→    return null;
 58→  }
 59→}
