 61→function extractPromotionRuntimePath(url: URL): string | null {
 62→  const host = url.hostname.toLowerCase();
 63→  const pathname = url.pathname;
 64→  const isGithubPromotionImage =
 65→    (host === 'github.com' && pathname.startsWith(GITHUB_PROMOTION_PATH_PREFIX)) ||
 66→    (host === 'raw.githubusercontent.com' &&
 67→      pathname.startsWith(RAW_GITHUBUSERCONTENT_PROMOTION_PATH_PREFIX));
 68→  if (!isGithubPromotionImage) return null;
 69→
 70→  const filename = pathname.split('/').pop();
 71→  return filename ? getPromotionRuntimePath(filename) : null;
 72→}
