 74→export function resolveChangelogImageUrl(
 75→  url: string,
 76→  runtimeUrlResolver: (path: string) => string | null = getRuntimeUrl,
 77→): string {
 78→  try {
 79→    const parsed = new URL(url);
 80→    const runtimePath = extractPromotionRuntimePath(parsed);
 81→    if (!runtimePath) return url;
 82→
 83→    const runtimeUrl = runtimeUrlResolver(runtimePath);
 84→    return runtimeUrl ?? url;
 85→  } catch {
 86→    return url;
 87→  }
 88→}
