 90→export function rewriteChangelogImageUrls(
 91→  markdown: string,
 92→  runtimeUrlResolver: (path: string) => string | null = getRuntimeUrl,
 93→  shouldRewrite: boolean = true,
 94→): string {
 95→  if (!shouldRewrite) return markdown;
 96→
 97→  return markdown.replace(MARKDOWN_IMAGE_URL_REGEX, (full, alt, url) => {
 98→    const resolvedUrl = resolveChangelogImageUrl(url, runtimeUrlResolver);
 99→    if (resolvedUrl === url) return full;
100→    return `![${alt}](${resolvedUrl})`;
101→  });
102→}
