104→/**
105→ * Strip optional front matter (--- ... ---) from markdown.
106→ */
107→function stripFrontMatter(raw: string): string {
108→  const match = raw.match(/^---\r?\n[\s\S]*?\r?\n---\r?\n([\s\S]*)$/);
109→  return match ? match[1] : raw;
110→}
