112→/**
113→ * Extract the section matching the user's language from a multi-language
114→ * markdown file. Falls back to 'en' if the requested language is missing.
115→ */
116→export function extractLocalizedContent(raw: string, lang: AppLanguage): string {
117→  const body = stripFrontMatter(raw);
118→
119→  // Split by <!-- lang:xx --> markers
120→  const sections = new Map<string, string>();
121→  const parts = body.split(/<!--\s*lang:(\w+)\s*-->/);
122→
123→  // parts[0] is text before the first marker (usually empty)
124→  // parts[1] = lang code, parts[2] = content, parts[3] = lang code, etc.
125→  for (let i = 1; i < parts.length; i += 2) {
126→    const langCode = parts[i];
127→    const content = parts[i + 1]?.trim() ?? '';
128→    if (langCode && content) {
129→      sections.set(langCode, content);
130→    }
131→  }
132→
133→  return sections.get(lang) ?? sections.get('en') ?? '';
134→}
