375→/**
376→ * Load and render the changelog modal.
377→ * @param version - Which version's changelog to show (defaults to EXTENSION_VERSION)
378→ * @param skipDismissCheck - Skip the dismissed-version check
379→ */
380→async function showChangelogModal(
381→  version = EXTENSION_VERSION,
382→  skipDismissCheck = false,
383→): Promise<HTMLDivElement | null> {
384→  // 1. Check dismissed version
385→  if (!skipDismissCheck) {
386→    const result = await chrome.storage.local.get(StorageKeys.CHANGELOG_DISMISSED_VERSION);
387→    const dismissedVersion = result[StorageKeys.CHANGELOG_DISMISSED_VERSION] as string | undefined;
388→    if (dismissedVersion === EXTENSION_VERSION) return null;
389→  }
390→
391→  // 2. Try to load the changelog for the target version
392→  const modulePath = `./notes/${version}.md`;
393→  const loader = changelogModules[modulePath];
394→  if (!loader) return null;
395→
396→  const rawMarkdown = await loader();
397→
398→  // 3. Get current language and extract localized content
399→  const lang = await getCurrentLanguage();
400→  const localizedContent = rewriteChangelogImageUrls(
401→    extractLocalizedContent(rawMarkdown, lang),
402→    getRuntimeUrl,
403→    isFirefox(),
404→  );
405→  if (!localizedContent) return null;
406→
407→  // 4. Convert markdown to HTML
408→  const rawHtml = await marked.parse(localizedContent);
409→  const sanitizedHtml = DOMPurify.sanitize(rawHtml, {
410→    ALLOWED_TAGS: [
411→      'h1',
412→      'h2',
413→      'h3',
414→      'h4',
415→      'h5',
416→      'h6',
417→      'p',
418→      'br',
419→      'hr',
420→      'ul',
421→      'ol',
422→      'li',
423→      'strong',
424→      'em',
425→      'code',
426→      'pre',
427→      'a',
428→      'img',
429→      'blockquote',
430→    ],
431→    ALLOWED_ATTR: ['href', 'target', 'rel', 'src', 'alt', 'class'],
432→  });
433→
434→  // 5. Inject modal
435→  const { overlay } = createChangelogModal(sanitizedHtml, lang);
436→  document.body.appendChild(overlay);
437→  return overlay;
438→}
