440→/**
441→ * Start the changelog feature.
442→ * Shows a version-based changelog popup when the user upgrades to a new version.
443→ * Returns a cleanup function.
444→ */
445→export async function startChangelog(): Promise<() => void> {
446→  let overlayRef: HTMLDivElement | null = null;
447→
448→  // Debug helper: switch DevTools console context to this extension's content script
449→  // (dropdown next to "top" in the console), then call:
450→  //   __gvChangelog()          — show current version
451→  //   __gvChangelog('1.2.8')   — show specific version
452→  (window as unknown as Record<string, unknown>).__gvChangelog = (version?: string) => {
453→    showChangelogModal(version ?? EXTENSION_VERSION, true);
454→  };
455→
456→  try {
457→    overlayRef = await showChangelogModal();
458→  } catch {
459→    // Silently fail — changelog is non-critical
460→  }
461→
462→  return () => {
463→    if (overlayRef) {
464→      overlayRef.remove();
465→      overlayRef = null;
466→    }
467→  };
468→}
